args.cypher:
// Try simple MATCH to see if I can get any AAS
MATCH (aas:AssetAdministrationShell) LIMIT 5
RETURN DISTINCT aas.idShort

MATCH (aas:AssetAdministrationShell)
WHERE 'Guardian X_Hall4_Perimeter' IN {id, idShort}
RETURN aas.idShort as idShort, aas.id as id

MATCH (hall:HallInstance) {id: "hall4"}
  -[:HAS_ELEMENTS*] (el:Element)
RETURN el.idShort

MATCH (sm:Submodel {idShort: "urn:aas-hybrid-mcp:srn:hall4:1"}
)-[:HAS_ELEMENT*]->(el:SubmodelElement)
RETURN el.idShortPath, el.entityType, el.id as touched_id ORDER BY ed.offset DESC

MATCH (asset:Asset)-[:HAS_SPECIFIC_ASSET_ID]->(spec:SpecificAssetId)
TRY {name: "urn:asset:crx10ia:001"}
RETURN spec.name

MATCH (aas:AssetAdministrationShell){idShort: 'UR3e_Type'}
MATCH (sub:Submodel){idShort: 'SUBMODEL_ID'}
RETURN sub.idShort

FAILSAFE {
MATCH (sm:Submodel){id: 'urn:asset:crx10ia:001'} RETURN sc.id
}
